/* Lightweight local Mermaid-compatible fallback for offline MVP demos.
   It renders Mermaid source as a readable boxed diagram when the full Mermaid lib is not bundled. */
(function () {
  function esc(s) { return String(s || '').replace(/[&<>]/g, function (c) { return ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' })[c]; }); }
  function renderNode(el) {
    if (!el || el.dataset.rendered === 'true') return;
    var code = el.textContent || '';
    var lines = code.split('\n').map(function (line) { return line.trim(); }).filter(Boolean);
    var items = lines.filter(function (line) { return !/^flowchart|^graph|^sequenceDiagram/i.test(line); }).slice(0, 14);
    if (!items.length) items = lines.slice(0, 14);
    var html = '<div class="mermaid-local-diagram"><div class="mermaid-local-title">Схема</div>' +
      items.map(function (line) { return '<div class="mermaid-local-row">' + esc(line) + '</div>'; }).join('') +
      '</div>';
    el.innerHTML = html;
    el.dataset.rendered = 'true';
  }
  window.mermaid = window.mermaid || {
    initialize: function () {},
    init: function () { document.querySelectorAll('.mermaid').forEach(renderNode); return Promise.resolve(); },
    run: function (opts) { document.querySelectorAll((opts && opts.querySelector) || '.mermaid').forEach(renderNode); return Promise.resolve(); }
  };
  document.addEventListener('DOMContentLoaded', function () { window.mermaid.run({ querySelector: '.mermaid' }); });
})();
